INSERT INTO `chat_history` VALUES (243, '2026-04-17 23:42:51.913974', '我面试紧张怎么办（简短回答）', 'USER', '2026-04-17 23:42:51.913974', 'default_user');
INSERT INTO `chat_history` VALUES (244, '2026-04-17 23:42:51.963519', '1. 提前模拟面试，熟悉流程和问题；2. 面试前深呼吸3-5次，调整节奏；3. 把面试官当成平等交流的人，减少压迫感；4. 专注于回答内容，而非自己的紧张情绪。', 'ASSISTANT', '2026-04-17 23:42:51.963519', 'default_user');
INSERT INTO `chat_history` VALUES (245, '2026-04-17 23:44:57.528747', '我面试紧张怎么办（简短回答）', 'USER', '2026-04-17 23:44:57.528747', 'default_user');
INSERT INTO `chat_history` VALUES (246, '2026-04-17 23:44:57.528747', '1. 提前模拟：对着镜子或找朋友演练面试场景，熟悉流程和话术；  \n2. 呼吸调节：紧张时缓慢深呼吸（4秒吸气+6秒呼气），平复心率；  \n3. 心态转换：把面试当成“双向沟通”，你也在评估公司是否适合自己；  \n4. 聚焦问题：专注于回答当前问题，别想“没答好怎么办”，减少杂念。  \n\n简单实用，亲测有效～', 'ASSISTANT', '2026-04-17 23:44:57.528747', 'default_user');

