INSERT INTO `job_postings` VALUES (73, 'Agent工程师', '测试', 3, '技术部', '广州', '全职', 10, 20, '月薪', '应届生', '本科及以上', '本科及以上学历，计算机科学、人工智能、软件工程、电子信息等相关专业，优秀本科生可放宽学历要求，有丰富Agent相关项目经验或硕士及以上学历且有NLP、多模态、强化学习等相关研究背景、发表过相关顶会论文者优先；需精通Python，熟悉Java/Go/TypeScript中至少一门语言，具备扎实的编程能力与系统设计能力，深入理解Agent核心原理，熟练使用至少一种主流Agent开发框架，理解LLM工作原理，掌握Prompt工程、Function Calling技巧，具备模型微调经验，熟悉容器化部署工具与服务开发框架，了解AI安全与合规相关要求；拥有1-3年及以上AI相关开发经验，至少1年Agent或LLM应用系统生产开发经验，有完整Agent项目从0到1落地、特定业务场景Agent落地或大规模Agent系统部署经验者优先；具备较强的问题解决能力、跨团队协作能力、持续学习意识及抗压能力，有良好的代码规范与文档编写习惯；深入理解Agent框架局限性、有相关特定Agent实践经验或在技术社区有开源项目、持有相关AI工程师认证者为加分项。', 'Agent工程师核心负责智能代理（AI Agent）系统的设计、开发、优化与落地，聚焦于让大语言模型（LLM）具备自主决策、任务规划、工具调用及多主体协作能力，将AI技术转化为可落地的业务解决方案，兼顾系统稳定性、安全性与工程化落地效率，推动Agent技术在实际业务场景中产生价值。', NULL, '', '', NULL, NULL, NULL, 'active', 3, 0, 1, NULL, 0, 0, '2026-04-18 17:13:53', '2026-04-18 17:14:12', '2026-04-18 17:13:53');

-- ----------------------------
-- Table structure for learning_resources
-- ----------------------------
DROP TABLE IF EXISTS `learning_resources`;
CREATE TABLE `learning_resources`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `author` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` datetime(6) NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `difficulty_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `duration` int NULL DEFAULT NULL,
  `is_free` bit(1) NULL DEFAULT NULL,
  `price` double NULL DEFAULT NULL,
  `rating` double NULL DEFAULT NULL,
  `resource_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `thumbnail_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `updated_at` datetime(6) NULL DEFAULT NULL,
  `url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `view_count` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 53 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

