  `id` bigint NOT NULL AUTO_INCREMENT,
  `based_on_interview_id` bigint NULL DEFAULT NULL,
  `completion_date` datetime(6) NULL DEFAULT NULL,
  `created_at` datetime(6) NULL DEFAULT NULL,
  `is_completed` bit(1) NULL DEFAULT NULL,
  `is_viewed` bit(1) NULL DEFAULT NULL,
  `priority_level` int NULL DEFAULT NULL,
  `recommendation_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `recommendation_score` double NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `updated_at` datetime(6) NULL DEFAULT NULL,
  `user_id` bigint NULL DEFAULT NULL,
  `user_rating` int NULL DEFAULT NULL,
  `weakness_areas` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `resource_id` bigint NOT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `FK2xlmqqr60w8ojelt69ca6kun4`(`resource_id` ASC) USING BTREE,
  CONSTRAINT `FK2xlmqqr60w8ojelt69ca6kun4` FOREIGN KEY (`resource_id`) REFERENCES `learning_resources` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 31 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

